import argparse
import json
import pickle
import numpy as np
import torch
from torchvision import transforms
from PIL import Image
from pathlib import Path
from tqdm import tqdm
import timm
from transformers import AutoModel

Image.MAX_IMAGE_PIXELS = None

TRANSFORMS = {
    'dinov2': transforms.Compose([
        transforms.Resize(224, interpolation=transforms.InterpolationMode.BICUBIC),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize([0.485, 0.456, 0.406], [0.229, 0.224, 0.225]),
    ]),
    'clip': transforms.Compose([
        transforms.Resize(224, interpolation=transforms.InterpolationMode.BICUBIC),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize([0.48145466, 0.4578275, 0.40821073],
                             [0.26862954, 0.26130258, 0.27577711]),
    ]),
    'resnet': transforms.Compose([
        transforms.Resize(256, interpolation=transforms.InterpolationMode.BILINEAR),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize([0.485, 0.456, 0.406], [0.229, 0.224, 0.225]),
    ]),
}

class TestDataset(torch.utils.data.Dataset):
    def __init__(self, txt_path, img_root, tfm):
        self.img_root = Path(img_root)
        self.tfm = tfm
        with open(txt_path) as f:
            self.samples = [l.strip() for l in f if l.strip()]
    def __len__(self):
        return len(self.samples)
    def __getitem__(self, idx):
        img = Image.open(self.img_root / self.samples[idx]).convert('RGB')
        return self.tfm(img)

@torch.no_grad()
def extract(model, loader, device, is_vit=False):
    model.eval()
    feats = []
    for imgs in tqdm(loader, desc='feat'):
        imgs = imgs.to(device)
        out = model(imgs)
        if is_vit and hasattr(out, 'last_hidden_state'):
            out = out.last_hidden_state[:, 0]
        # hflip TTA
        out2 = model(torch.flip(imgs, dims=[3]))
        if is_vit and hasattr(out2, 'last_hidden_state'):
            out2 = out2.last_hidden_state[:, 0]
        f = ((out + out2) / 2).cpu().numpy()
        feats.append(f)
    return np.concatenate(feats, axis=0)

def normalize(feats):
    return feats / (np.linalg.norm(feats, axis=1, keepdims=True) + 1e-8)

def inspect_needs(obj, needs):
    if isinstance(obj, dict):
        if 'prototypes' in obj:
            dim = obj['prototypes'].shape[-1]
        elif 'items' in obj:
            for item in obj['items']:
                inspect_needs(item, needs)
            return
        elif 'clfs' in obj:
            inspect_needs(obj['clfs'], needs)
            return
        else:
            return
    elif isinstance(obj, list) and len(obj) > 0 and hasattr(obj[0], 'coef_'):
        dim = obj[0].coef_.shape[1]
    elif hasattr(obj, 'coef_'):
        dim = obj.coef_.shape[1]
    else:
        return
    if dim == 768:
        needs.add('dinov2')
    elif dim == 2048:
        needs.add('resnet')
    elif dim == 2816:
        needs.update(['dinov2', 'resnet'])
    elif dim == 3584:
        needs.update(['dinov2', 'resnet', 'clip'])

def get_probs(obj, fm):
    if isinstance(obj, dict) and 'items' in obj:
        total = None
        for item in obj['items']:
            p = get_probs(item, fm) * item['weight']
            total = p if total is None else total + p
        return total
    if isinstance(obj, dict) and 'prototypes' in obj:
        protos = obj['prototypes']
        X = fm.get(3584) or fm.get('all')
        scores = np.zeros((len(X), 10))
        for d in range(len(protos)):
            s = X @ protos[d].T
            e = np.exp(s - np.max(s, axis=1, keepdims=True))
            scores += e / np.sum(e, axis=1, keepdims=True)
        return scores / len(protos)
    if isinstance(obj, dict) and 'clfs' in obj:
        obj = obj['clfs']
    if isinstance(obj, list) and len(obj) > 0 and hasattr(obj[0], 'coef_'):
        probs = np.zeros((len(next(iter(fm.values()))), 10))
        for clf in obj:
            dim = clf.coef_.shape[1]
            X = fm.get(dim) or fm.get('all')
            probs += clf.predict_proba(X)
        return probs / len(obj)
    if hasattr(obj, 'coef_'):
        dim = obj.coef_.shape[1]
        X = fm.get(dim) or fm.get('all')
        return obj.predict_proba(X)
    raise ValueError('Unsupported checkpoint format')

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    data_path = Path(args.data_path)
    with open(args.checkpoint, 'rb') as f:
        ckpt = pickle.load(f)

    needs = set()
    inspect_needs(ckpt, needs)
    print(f'Needed backbones: {needs}')

    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    models = {}
    if 'dinov2' in needs:
        print('Loading DINOv2...')
        m = AutoModel.from_pretrained('facebook/dinov2-base')
        models['dinov2'] = (m.to(device).eval(), True)
    if 'resnet' in needs:
        print('Loading ResNet50...')
        import torchvision.models as tvm
        m = tvm.resnet50(weights='IMAGENET1K_V2')
        m.fc = torch.nn.Identity()
        models['resnet'] = (m.to(device).eval(), False)
    if 'clip' in needs:
        print('Loading CLIP...')
        m = timm.create_model('vit_base_patch16_clip_224.openai', pretrained=True, num_classes=0)
        models['clip'] = (m.to(device).eval(), True)

    test_txt = data_path / 'test.txt'
    img_root = data_path / 'images'

    feats_map = {}
    all_feats = []
    if 'dinov2' in needs:
        ds = TestDataset(test_txt, img_root, TRANSFORMS['dinov2'])
        loader = torch.utils.data.DataLoader(ds, batch_size=128, num_workers=4, pin_memory=True)
        f = normalize(extract(models['dinov2'][0], loader, device, models['dinov2'][1]))
        feats_map[768] = f
        all_feats.append(f)
    if 'resnet' in needs:
        ds = TestDataset(test_txt, img_root, TRANSFORMS['resnet'])
        loader = torch.utils.data.DataLoader(ds, batch_size=128, num_workers=4, pin_memory=True)
        f = normalize(extract(models['resnet'][0], loader, device, models['resnet'][1]))
        feats_map[2048] = f
        all_feats.append(f)
    if 'clip' in needs:
        ds = TestDataset(test_txt, img_root, TRANSFORMS['clip'])
        loader = torch.utils.data.DataLoader(ds, batch_size=128, num_workers=4, pin_memory=True)
        f = normalize(extract(models['clip'][0], loader, device, models['clip'][1]))
        all_feats.append(f)

    if len(all_feats) > 1:
        concat = np.concatenate(all_feats, axis=1)
        feats_map['all'] = concat
        if concat.shape[1] == 2816:
            feats_map[2816] = concat
        elif concat.shape[1] == 3584:
            feats_map[3584] = concat

    probs = get_probs(ckpt, feats_map)
    preds = np.argmax(probs, axis=1).tolist()

    with open(args.output, 'w') as f:
        json.dump({'predictions': preds}, f)
    print(f'Saved {len(preds)} predictions to {args.output}')

if __name__ == '__main__':
    main()
